import React, { useState } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { updateProfile } from '../redux/slices/authSlice';
import { logoutUser } from '../redux/thunks/authThunks';
import { dotnetApi } from '../api/axios';
import { ENDPOINTS } from '../api/config';
import { toast } from 'react-toastify';
import './Settings.css';

const Settings = () => {
  const { user } = useSelector((state) => state.auth);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const [userType, setUserType] = useState(user?.usertype || '0'); // 0=normal, 1=dating
  const [switching, setSwitching] = useState(false);

  const handleSwitchType = async () => {
    const newType = userType === '0' ? '1' : '0';
    setSwitching(true);
    try {
      await dotnetApi.post(ENDPOINTS.UPDATE_USER_TYPE, {
        user_id: user?._id,
        user_type: newType,
      });
      setUserType(newType);
      dispatch(updateProfile({ usertype: newType }));
      toast.success(newType === '1' ? 'Switched to Dating mode' : 'Switched to Social mode');
    } catch (error) {
      toast.error('Failed to switch mode');
    }
    setSwitching(false);
  };

  const handleLogout = () => {
    dispatch(logoutUser());
    navigate('/login');
  };

  return (
    <div className="settings-page">
      <div className="settings-header">
        <button className="settings-back" onClick={() => navigate(-1)}>←</button>
        <h1 className="settings-title">Settings</h1>
      </div>

      <div className="settings-list">
        {/* Profile Type */}
        <div className="settings-item">
          <div className="settings-item-info">
            <span className="settings-item-label">Profile Mode</span>
            <span className="settings-item-value">
              {userType === '1' ? 'Dating' : 'Social'}
            </span>
          </div>
          <button
            className="settings-switch-btn"
            onClick={handleSwitchType}
            disabled={switching}
          >
            {switching ? '...' : `Switch to ${userType === '1' ? 'Social' : 'Dating'}`}
          </button>
        </div>

        {/* Navigation items */}
        <div className="settings-item" onClick={() => navigate('/profile/edit')}>
          <span className="settings-item-label">✏️ Edit Profile</span>
          <span className="settings-item-arrow">→</span>
        </div>

        <div className="settings-item" onClick={() => navigate('/portfolio')}>
          <span className="settings-item-label">📁 Portfolio</span>
          <span className="settings-item-arrow">→</span>
        </div>

        <div className="settings-item" onClick={() => navigate('/subscriptions')}>
          <span className="settings-item-label">💳 Subscriptions</span>
          <span className="settings-item-arrow">→</span>
        </div>

        <div className="settings-item" onClick={() => navigate('/support')}>
          <span className="settings-item-label">❓ Support</span>
          <span className="settings-item-arrow">→</span>
        </div>

        <div className="settings-item" onClick={() => navigate('/tutorials')}>
          <span className="settings-item-label">📖 Tutorials</span>
          <span className="settings-item-arrow">→</span>
        </div>

        {/* Logout */}
        <div className="settings-item settings-logout" onClick={handleLogout}>
          <span className="settings-item-label">🚪 Logout</span>
        </div>
      </div>
    </div>
  );
};

export default Settings;
